// SecurityConfig.java - Deshabilitar CSRF para API stateless
@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) 
            throws Exception {
        http
            .httpBasic()
            .and()
            // Deshabilitar CSRF para API REST stateless
            .csrf().disable()
            .authorizeHttpRequests(auth -> auth
                // Endpoints públicos
                .requestMatchers("/actuator/health").permitAll()
                .requestMatchers("/swagger-ui/**", "/v3/api-docs/**").permitAll()

                // GET requiere rol USER
                .requestMatchers(HttpMethod.GET, "/api/v1/**")
                    .hasRole("USER")

                // POST/PUT/DELETE requieren rol ADMIN
                .requestMatchers(HttpMethod.POST, "/api/v1/**")
                    .hasRole("ADMIN")
                .requestMatchers(HttpMethod.PUT, "/api/v1/**")
                    .hasRole("ADMIN")
                .requestMatchers(HttpMethod.DELETE, "/api/v1/**")
                    .hasRole("ADMIN")

                // Resto requiere autenticación
                .anyRequest().authenticated()
            );

        return http.build();
    }

    @Bean
    public UserDetailsService userDetailsService() {
        // Usuario con rol USER
        UserDetails user = User.builder()
            .username("user")
            .password("{noop}user123")
            .roles("USER")
            .build();

        // Usuario con rol ADMIN
        UserDetails admin = User.builder()
            .username("admin")
            .password("{noop}admin123")
            .roles("USER", "ADMIN")  // ADMIN incluye USER
            .build();

        return new InMemoryUserDetailsManager(user, admin);
    }
}

// Alternativa: Mantener CSRF habilitado (APIs con sesión)
@Bean
public SecurityFilterChain securityFilterChain(HttpSecurity http) 
        throws Exception {
    http
        .httpBasic()
        .and()
        // CSRF habilitado (por defecto)
        .csrf(csrf -> csrf
            .csrfTokenRepository(CookieCsrfTokenRepository.withHttpOnlyFalse())
        )
        .authorizeHttpRequests(auth -> auth
            .anyRequest().authenticated()
        );

    return http.build();
}

