// SecurityConfig.java - Configurar CORS
@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) 
            throws Exception {
        http
            .httpBasic()
            .and()
            .csrf().disable()

            // Habilitar CORS con configuración personalizada
            .cors(cors -> cors.configurationSource(corsConfigurationSource()))

            .sessionManagement(session -> session
                .sessionCreationPolicy(SessionCreationPolicy.STATELESS)
            )
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/actuator/health").permitAll()
                .requestMatchers("/swagger-ui/**", "/v3/api-docs/**").permitAll()
                .anyRequest().authenticated()
            );

        return http.build();
    }

    @Bean
    public CorsConfigurationSource corsConfigurationSource() {
        CorsConfiguration configuration = new CorsConfiguration();

        // Orígenes permitidos (desarrollo)
        configuration.setAllowedOrigins(Arrays.asList(
            "http://localhost:3000",      // React dev server
            "http://localhost:4200",      // Angular dev server
            "http://localhost:8080"       // Vue dev server
        ));

        // Producción: especificar dominio exacto
        // configuration.setAllowedOrigins(Arrays.asList(
        //     "https://app.paymentchange.com"
        // ));

        // Métodos permitidos
        configuration.setAllowedMethods(Arrays.asList(
            "GET", "POST", "PUT", "DELETE", "OPTIONS"
        ));

        // Headers permitidos
        configuration.setAllowedHeaders(Arrays.asList(
            "*"  // Permitir todos los headers
            // O específicos: "Authorization", "Content-Type", "X-Requested-With"
        ));

        // Permitir envío de credenciales (cookies, auth headers)
        configuration.setAllowCredentials(true);

        // Tiempo de cache para preflight (1 hora)
        configuration.setMaxAge(3600L);

        // Aplicar configuración a todos los endpoints
        UrlBasedCorsConfigurationSource source = 
            new UrlBasedCorsConfigurationSource();
        source.registerCorsConfiguration("/**", configuration);

        return source;
    }

    // ... resto de beans (PasswordEncoder, UserDetailsService)
}

