// CustomerService.java - Uso normal, autenticación automática
@Service
public class CustomerService {

    @Autowired
    private WebClient productWebClient;

    public Product getProduct(Long productId) {
        // WebClient incluye automáticamente header Authorization
        return productWebClient.get()
            .uri("/product/{id}", productId)
            .retrieve()
            .bodyToMono(Product.class)
            .block();

        // Header Authorization: Basic YWRtaW46YWRtaW4xMjM=
        // se agrega automáticamente
    }
}

// Alternativa producción: OAuth2 Client Credentials
// (requiere servidor OAuth2/Authorization Server)
@Bean
public WebClient productWebClientOAuth2(WebClient.Builder builder,
                                       OAuth2AuthorizedClientManager clientManager) {
    ServletOAuth2AuthorizedClientExchangeFilterFunction oauth2 = 
        new ServletOAuth2AuthorizedClientExchangeFilterFunction(clientManager);
    oauth2.setDefaultClientRegistrationId("product-service");

    return builder
        .baseUrl("http://product-service/api/v1")
        .filter(oauth2)
        .build();
}
